INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('行政专员 - 拉萨（社招）', '其他', '拉萨', '民营企业', 5000, 7000, '熟练使用办公软件，具备基础文档处理能力', '沟通能力良好，具备服务意识和协调能力；工作细致认真，责任心强，能高效完成任务', 1, '友好', '1. 处理日常行政事务，维护高效有序的办公环境；2. 协助组织会议、活动及来访接待，确保流程顺畅；3. 整理归档行政资料，保持办公区域整洁规范', '行政事务支持、会议活动组织、接待外联', '大专及以上', '无强制专业限制', '1-3年相关工作经验', '社招（应届生可投）', '有旅游/酒店行业行政工作经验；有接待、活动组织相关经验', '5k-7k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员 - 昌吉回族自治州（社招）', '化工 / 能源 / 环保', '昌吉回族自治州', '民营企业', 4000, 7000, '熟练使用Office办公软件', '沟通能力良好，能有效协调内外部事务；工作细致耐心，具备较强的责任心和服务意识；适应快节奏工作环境，具备良好的执行力', 1, '友好', '1. 协助处理公司日常行政事务及流程管理；2. 负责文件整理、会议安排与信息传达；3. 确保办公设备及资源的合理调配与使用', '行政事务支持、会议活动组织、固定资产管理', '大专及以上', '无强制专业限制', '经验不限', '社招（应届生可投）', '具备财务经验；有接待外联相关经验', '4k-7k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员 - 广州（社招）', '快消', '广州', '民营企业', 7000, 9000, '熟悉常用办公软件操作，具备良好的文书处理能力', '形象端正，性格开朗，具备出色的服务意识与沟通协调能力；工作细心负责，积极主动，能适应快节奏的工作环境；具备良好的团队合作精神，执行力强', 0, '一般', '1. 负责前台接待、电话接转、收发快递，维护公司良好第一印象；2. 负责办公用品、饮用水等的采购、发放及库存管理，保障日常办公需求；3. 维护办公区环境整洁，监督保洁工作，管理办公设备报修等事宜；4. 协助组织员工活动、会议，并负责相关后勤支持工作；5. 管理公司固定资产及行政仓库，定期完成盘点工作；6. 完成上级交办的其它事务', '行政事务支持、接待外联、固定资产管理、会议活动组织、物品采购管理', '大专及以上', '人力资源、酒店管理等相关专业优先', '1-3年，2年以上行政、前台或文秘相关工作经验', '社招（应届生可投）', '有行政相关证书；有快消行业行政工作经验', '7k-9k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员（车管员） - 黔南布依族苗族自治州（社招）', '其他', '黔南布依族苗族自治州', '民营企业', 3000, 4000, '熟练使用办公软件，能够准确完成台账登记与数据整理工作；熟悉车辆管理相关法规及物流运输行业基本运作流程', '具备良好的沟通协调能力，能与司机、维修单位及相关职能部门有效对接；责任心强，具备较强的执行力和应急处理能力', 1, '友好', '1. 负责公司车辆的日常管理与调度安排，确保车辆运行有序、高效；2. 监督车辆的维护保养及定期年检、保险等手续办理，保障车辆合规上路；3. 跟踪车辆使用状态，记录行驶里程、保养、维修等数据，建立完善车辆档案；4. 协调处理车辆事故等突发情况，跟进后续处理流程；5. 有序完成车辆年审、维护、罐检、保险、车辆新增、过户、报停及恢复营运、档案排查及系统录入工作', '行政事务支持、固定资产管理、应急事务处理', '大专及以上', '无强制专业限制', '1-3年相关工作经验', '社招（应届生可投）', '有物流行业车辆管理经验；有相关行政证书', '3k-4k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员/助理 - 辽阳（社招）', '互联网 / IT', '辽阳', '民营企业', 3000, 5000, '熟悉办公软件的使用', '具备良好的沟通能力和团队协作精神；具有较强的组织和协调能力；能够有效地协助团队完成工作', 1, '友好', '1. 负责日常办公室行政管理工作；2. 协助团队成员完成项目协调与支持；3. 处理公司内外的沟通事务；4. 参与公司活动的策划与执行', '行政事务支持、会议活动组织、跨部门协调', '本科及以上', '无强制专业限制', '1-3年相关工作经验', '社招（应届生可投）', '有电商行业行政工作经验；有活动策划相关经验', '3k-5k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）');